SELECT COUNT(*) FROM invoice
WHERE FORMATDATETIME(issue_date, 'yyyy-MM') = #{month}
AND invoice_kind = #{kind}
AND status IN ('ISSUED', 'DELIVERED', 'RED_CANCELLED')

SELECT COALESCE(SUM(total_amount), 0) FROM invoice
WHERE FORMATDATETIME(issue_date, 'yyyy-MM') = #{month}
AND invoice_kind = #{kind}
AND status IN ('ISSUED', 'DELIVERED', 'RED_CANCELLED')

SELECT COALESCE(SUM(total_amount), 0) FROM invoice
WHERE invoice_kind = #{kind}
AND status IN ('ISSUED', 'DELIVERED', 'RED_CANCELLED')

SELECT i.* FROM invoice i


        AND i.status = #{status}


        AND i.issue_date >= #{startDate}


        AND i.issue_date <= #{endDate}


        AND i.id IN (SELECT invoice_id FROM invoice_detail WHERE contract_no LIKE CONCAT('%', #{contractNo}, '%'))


        AND i.invoice_type = #{invoiceType}


ORDER BY i.created_at DESC
LIMIT #{offset}, #{limit}
